import{o as e,c as a,b as t}from"./app.3132835d.js";const s='{"title":"git多用户配置","description":"开发时遇到需要多个git账号配置，例如是github和gitlab之类的，不同的用户连接不同的仓库。那么要如何去配置呢？","frontmatter":{"title":"git多用户配置","date":"2020-03-13","tags":["Git"],"description":"开发时遇到需要多个git账号配置，例如是github和gitlab之类的，不同的用户连接不同的仓库。那么要如何去配置呢？"},"headers":[{"level":2,"title":"遇到的情形","slug":"遇到的情形"},{"level":2,"title":"如何解决","slug":"如何解决"},{"level":3,"title":"1.首先CD到.ssh目录下生成不同的sshkey","slug":"_1-首先cd到-ssh目录下生成不同的sshkey"},{"level":3,"title":"2.配置config文件","slug":"_2-配置config文件"},{"level":3,"title":"3.查看是否配置成功","slug":"_3-查看是否配置成功"},{"level":3,"title":"4.切换用户","slug":"_4-切换用户"},{"level":2,"title":"最后","slug":"最后"}],"relativePath":"blog/gitUser.md","lastUpdated":1620378953540}',n={},i=t('<h2 id="遇到的情形"><a class="header-anchor" href="#遇到的情形" aria-hidden="true">#</a> 遇到的情形</h2><p>在公司开发时遇到需要多个git账号配置，例如是github和gitlab之类的，不同的用户连接不同的仓库</p><table><thead><tr><th></th><th style="text-align:center;">github</th><th style="text-align:center;">gitlab</th></tr></thead><tbody><tr><td>user</td><td style="text-align:center;">a</td><td style="text-align:center;">b</td></tr><tr><td>email</td><td style="text-align:center;"><a href="mailto:a@xx.com">a@xx.com</a></td><td style="text-align:center;"><a href="mailto:b@xx.com">b@xx.com</a></td></tr></tbody></table><h2 id="如何解决"><a class="header-anchor" href="#如何解决" aria-hidden="true">#</a> 如何解决</h2><h3 id="_1-首先cd到-ssh目录下生成不同的sshkey"><a class="header-anchor" href="#_1-首先cd到-ssh目录下生成不同的sshkey" aria-hidden="true">#</a> 1.首先CD到.ssh目录下生成不同的sshkey</h3><div class="language-bash"><pre><code>ssh-keygen -t rsa -C <span class="token string">&quot;changeme@xxx.com&quot;</span> -f filename\n<span class="token comment">#filename是生成文件的名称,例如可以填写id_ras_github,不加-f filename则会覆盖默认的id_rsa文件</span>\n</code></pre></div><p>绑定公钥常规步骤就略过了</p><h3 id="_2-配置config文件"><a class="header-anchor" href="#_2-配置config文件" aria-hidden="true">#</a> 2.配置config文件</h3><p>在.ssh下创建config文件</p><div class="language-bash"><pre><code><span class="token comment"># Linux/Mac</span>\n<span class="token function">touch</span> config\n<span class="token comment"># Windows，NUL大小写不敏感</span>\n<span class="token builtin class-name">type</span> nul <span class="token operator">&gt;</span> config\n</code></pre></div><p>config内如何配置呢</p><div class="language-"><pre><code>Host github.com\nHostName github.com\nUser a\nIdentityFile ~/.ssh/id_rsa_github\n\nHost gitlab.mygitlab.com\nHostName gitlab.mygitlab.com\nUser b\nIdentityFile ~/.ssh/id_rsa_gitlab\n</code></pre></div><ul><li>Host：仓库网站的别名 ，可以替代 HostName 来使用的别名，比如clone github 上某个仓库,之前的命令为</li></ul><div class="language-bash"><pre><code><span class="token function">git</span> clone git@github.com:a/xxx.git\n</code></pre></div><p>用Host设置为github后就变成</p><div class="language-bash"><pre><code><span class="token function">git</span> clone git@github:a/xxx.git\n</code></pre></div><p>为了方便使用还是直接设置成一样比较好</p><ul><li>HostName：设置域名地址或ip地址</li><li>User：仓库网站上的用户名</li><li>IdentityFile：输入id_rsa_xxx的目录地址</li></ul><h3 id="_3-查看是否配置成功"><a class="header-anchor" href="#_3-查看是否配置成功" aria-hidden="true">#</a> 3.查看是否配置成功</h3><div class="language-bash"><pre><code><span class="token function">ssh</span> -T git@gitlab\n<span class="token function">ssh</span> -T git@github\n</code></pre></div><h3 id="_4-切换用户"><a class="header-anchor" href="#_4-切换用户" aria-hidden="true">#</a> 4.切换用户</h3><p>上一步都成功后，配置就已经基本成功了 可以配置全局默认的用户</p><div class="language-bash"><pre><code><span class="token function">git</span> config --global user.name a\n<span class="token function">git</span> config --global user.email a@xx.com\n</code></pre></div><p>然后切换用户的话，在本地仓库根目录下配置</p><div class="language-bash"><pre><code><span class="token function">git</span> config --local user.name b\n<span class="token function">git</span> config --local user.email b@xx.com\n</code></pre></div><p>设置好之后可以通过</p><div class="language-bash"><pre><code><span class="token function">git</span> config --local --list\n</code></pre></div><p>查看本地仓库的配置信息，此时提交就是你刚才所配置的用户了</p><h2 id="最后"><a class="header-anchor" href="#最后" aria-hidden="true">#</a> 最后</h2><p>git官网config文档那么一大串真的看得头痛，这是我查阅些许网站后总结的，希望能有所帮助。</p>',30);n.render=function(t,s,n,l,c,o){return e(),a("div",null,[i])};export default n;export{s as __pageData};
